/* Input to this function is a string containing multiple groups of nested parentheses. Your goal is to
  separate those group into separate strings and return the list of those.
  Separate groups are balanced (each open brace is properly closed) and not nested within each other
  Ignore any spaces in the input string.
  >>> separateParenGroups('( ) (( )) (( )( ))')
  ['()', '(())', '(()())']
  */
const separateParenGroups = (paren_string) => {
  const paren_list = paren_string.split(' ')
  const paren_groups = []
  let paren_group = ''
  for (let i = 0, l = paren_list.length; i < l; i++) {
    if (paren_list[i] === '(') {
      paren_group += paren_list[i]
    } else if (paren_list[i] === ')') {
      paren_group += paren_list[i]
      paren_groups.push(paren_group)
      paren_group = ''
    }
  }
  return paren_groups
}

module.exports = separateParenGroups

canonical_solution:
  var result = [];
  var current_string = [];
  var current_depth = 0;

  for (const c of paren_string) {
    if (c == '(') {
      current_depth += 1;
      current_string.push(c);
    } else if (c == ')') {
      current_depth -= 1;
      current_string.push(c);
      if (current_depth == 0) {
        result.push(current_string.join(''));
        current_string = [];
      }
    }
  }

  return result;
}

