  >>> primeFib(1)
  2
  >>> primeFib(2)
  3
  >>> primeFib(3)
  5
  >>> primeFib(4)
  13
  >>> primeFib(5)
  89
  */
const primeFib = (n) => {
  const fib = (n) => {
    if (n === 0) return 0
    if (n === 1) return 1
    return fib(n - 1) + fib(n - 2)
  }
  const isPrime = (n) => {
    if (n === 1) return false
    for (let i = 2, s = Math.sqrt(n); i <= s; i++) {
      if (n % i === 0) return false
    }
    return true
  }
  const fibNum = fib(n)
  return isPrime(fibNum)? fibNum : primeFib(n + 1)
}

module.exports = primeFib

