const prodSigns = (arr) => {
  if (arr.length === 0) return null
  let sum = 0
  let prod = 1
  for (let i = 0, len = arr.length; i < len; i++) {
    if (arr[i] === 0) return 0
    if (arr[i] > 0) {
      prod = prod * 1
    } else {
      prod = prod * -1
    }
  }
  for (let i = 0, len = arr.length; i < len; i++) {
    if (arr[i] === 0) return 0
    sum = sum + arr[i] * prod
  }
  return sum
}

